const SOPS = {
  '10-SOP': {
    nom: 'Vérification OOB & Accès management',
    objectif: "Confirmer l\'accès OOB, Lightsoft et les accès management. Prérequis universel — à déclencher en premier sur tout incident.",
    steps: [
      "Ping gateway OOB — Depuis la station NOC, ping 10.0.0.1. Timeout = problème réseau OOB.",
      "Ouvrir Lightsoft — URL: http://lightsoft.internal — login admin.",
      "Vérifier alarmes actives — Menu Supervision > Alarmes. Noter criticité et heure.",
      "Tester accès SSH équipements — ssh admin@<node-ip> sur chaque châssis concerné. Timeout = vérifier règles firewall Lugos.",
      "Vérifier firewall Lugos si CLI KO — lugos show rules | grep management. Confirmer IPs NOC autorisées."
    ]
  },
  '11-SOP': {
    nom: 'Analyse Optique SFP',
    objectif: "Analyser les compteurs PM (FEC/BER/ES/SES) et la puissance optique SFP sur les ports OTN.",
    steps: [
      "Lightsoft > PM Counters — Sélectionner port > onglet Performance Monitoring > période 24h.",
      "Lire FEC corrected/uncorrected — FEC corrected en hausse = dégradation optique. Uncorrected > 0 = critique.",
      "Vérifier BER pre/post FEC — Pre-FEC BER > 1e-3 = problème signal. Post-FEC BER > 0 = urgence.",
      "Analyser ES / SES sur 24h — ES < 0.4% sur 24h (ITU-T G.826). SES < 0.05%. Dépassement = dégradation confirmée.",
      "Mesurer puissance optique SFP — Power meter sur connecteur d\'entrée port concerné. Comparer aux specs SFP constructeur."
    ]
  },
  '12-SOP': {
    nom: 'Test Viavi E2E',
    objectif: "Test de validation RFC 2544 / OTU2 E2E après remplacement physique ou troubleshooting client.",
    steps: [
      "Connecter le Viavi MTS-5800 — Port OTU2 du MTS-5800 sur le port UNI/NNI à valider. Mode: OTU2 10.7G.",
      "Configurer le test RFC 2544 — Throughput, Latency, Frame Loss, Back-to-Back. Taille trames: 64, 128, 256, 512, 1024, 1518 bytes.",
      "Lancer le test — Durée minimale: 60s par taille de trame. Enregistrer les résultats.",
      "Valider les seuils — Throughput > 99.9%. Latency < 1ms. Frame Loss = 0%. B2B > 90 frames.",
      "Exporter le rapport Viavi — MTS-5800 > Reports > Export PDF. Joindre au rapport d\'intervention final."
    ]
  },
  '13-SOP': {
    nom: 'Remplacement matériel (carte + SFP)',
    objectif: "Remplacement d\'une carte service (LB/HB/VHB) ou d\'un SFP défectueux sur châssis Ribbon Apollo.",
    steps: [
      "Confirmer la panne — Lightsoft : carte en état FAILED ou MISMATCH, ou SFP en LOS persistant.",
      "Prévoir le spare — Vérifier stock spare. Référence carte : étiquette châssis. Même référence SFP (λ, portée).",
      "Informer les clients affectés — Identifier les ports UNI/NNI impactés. Notifier avant intervention.",
      "Extraire le matériel défaillant — Déverrouiller la carte ou SFP. ESD obligatoire. Tirer avec précaution.",
      "Insérer le matériel de remplacement — Insérer jusqu\'au clic. Lightsoft : état IN-SERVICE sous 2 min.",
      "Valider E2E — 12-SOP (Test Viavi E2E) obligatoire pour confirmation service."
    ]
  },
  '14-SOP': {
    nom: 'Diagnostic signal OTN (OSNR + FEC/BER)',
    objectif: "Diagnostic complet signal OTN : OSNR, SPAN LOSS, FEC/BER et gestion bascule OLP.",
    steps: [
      "Ouvrir Lightsoft > Supervision — Menu Supervision > Vue topologie > sélectionner le lien concerné.",
      "Relever OSNR — Colonne OSNR doit être > 12 dB sur chaque canal. Valeur < 10 dB = critique.",
      "Mesurer SPAN LOSS — Span Loss = différence Tx/Rx en dBm. Seuil normal < 20 dB.",
      "Vérifier protection OLP — Lightsoft > Protection > état Working/Protect. Si bascule active : identifier chemin Working et cause.",
      "Inspecter connecteurs et SFP — Si SPAN LOSS élevé : nettoyer connecteurs SC/PC (kit IBC). Power meter sur port."
    ]
  },
  '15-SOP': {
    nom: 'Escalade Constructeur (Ribbon)',
    objectif: "Ouvrir un SR Ribbon TAC si l\'incident n\'est pas résolu après 10-SOP ou 11-SOP.",
    steps: [
      "Préparer les informations — Numéro de châssis, version logicielle, alarmes actives, logs GCC.",
      "Créer le SR — Portal : support.ribboncommunications.com > Create Service Request.",
      "Envoyer les logs — Lightsoft > Export > System Logs (24h). Joindre au SR."
    ]
  },
  '16-SOP': {
    nom: 'Escalade Supervision (Lugos)',
    objectif: "Escalade vers l\'équipe supervision Lugos si l\'incident persiste après 10-SOP.",
    steps: [
      "Documenter l\'incident — Consigner symptômes, heure de début, SOPs déjà appliquées et résultats.",
      "Contacter Lugos NOC — Ticket portail Lugos avec logs Lightsoft. Indiquer criticité et clients impactés.",
      "Suivre le cas — Mettre à jour le ticket toutes les 30 min. Escalade niveau 2 si pas de réponse sous 1h."
    ]
  },
  '17-SOP': {
    nom: 'Escalade Opérateur',
    objectif: "Escalade vers l\'opérateur (Cogent / EuNetwork) pour incident LOS ou bascule OLP non résolu.",
    steps: [
      "Confirmer l\'origine opérateur — Isoler : LOS sur plusieurs NNI ou OLP déclenché côté opérateur (pas côté équipement).",
      "Contacter le NOC opérateur — Cogent NOC : ticket portail / hotline. EuNetwork NOC : portail dédié.",
      "Fournir les métriques — OSNR, puissance Rx, heure et durée de l\'incident. Résultats 14-SOP joints.",
      "Documenter — Référence ticket opérateur dans le rapport d\'incident final."
    ]
  }
};
const PHASE_MAP = {'10-SOP': 1, '11-SOP': 2, '12-SOP': 5, '13-SOP': 3, '14-SOP': 2, '15-SOP': 4, '16-SOP': 4, '17-SOP': 4};
const PHASES = {"1": {"nom": "Pré-requis", "desc": "Vérifier accès OOB et management avant toute intervention.", "color": "#1a3a5c"}, "2": {"nom": "Diagnostic", "desc": "Identifier la cause racine par des vérifications techniques ciblées.", "color": "#2c5f8a"}, "3": {"nom": "Intervention", "desc": "Remplacer ou reconfigurer le matériel défaillant.", "color": "#3a5a8a"}, "4": {"nom": "Escalade", "desc": "Escalader vers constructeur, supervision ou opérateur si l\'incident persiste.", "color": "#4a4a8a"}, "5": {"nom": "Validation", "desc": "Valider la conformité du lien restauré par test E2E.", "color": "#2e7d32"}};
const body = $input.first().json.body || $input.first().json;
const {
  incident_id, incident_type, sous_type, criticite, sops,
  site, equipment, technicien, date_intervention, heure_debut,
  symptome, impact, cause_probable,
  alarme_lightsoft, alarme_vizee,
  contexte_kb, cas_reels, reseau, categorie
} = body;

const sopsArr = typeof sops === 'string'
  ? sops.split(',').map(s => s.trim()).filter(Boolean)
  : (Array.isArray(sops) ? sops : []);

// Build phase groups
const phaseGroups = {};
for (const s of sopsArr) {
  const ph = PHASE_MAP[s] || 2;
  if (!phaseGroups[ph]) phaseGroups[ph] = [];
  phaseGroups[ph].push(s);
}
const phaseNums = Object.keys(phaseGroups).map(Number).sort();

// Criticité CSS class
const critClass = criticite === 'MINEUR' ? 'crit-mineur'
  : criticite === 'MAJEUR' ? 'crit-majeur'
  : criticite === 'CRITIQUE' ? 'crit-critique' : '';
const critValueClass = 'crit-value-' + (critClass.replace('crit-', '') || 'majeur');

// Date/time
const dateStr = date_intervention || '____________________';
const heureStr = heure_debut || '________';
const techStr = technicien || '________________________';
const genTime = new Date().toISOString().replace('T', ' ').slice(0, 16) + ' UTC';
const docId = 'MOP-' + (incident_id || 'XXX');
const filename = 'mop-' + (incident_id || 'xxx').toLowerCase() + '.pdf';
const docxFilename = 'mop-' + (incident_id || 'xxx').toLowerCase() + '.docx';

// Helper: escape HTML
function esc(s) {
  return String(s || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
}

// Criticité banner
const critBannerHtml = `<div class="crit-banner ${critClass}">
  <div><div class="crit-label">Criticité</div><div class="${critValueClass}">${esc(criticite || 'N/A')}</div></div>
  <div style="flex:1"><div class="crit-label">Catégorie</div><div class="crit-cat">${esc(categorie || incident_type || 'N/A')} — ${esc(sous_type || 'N/A')}</div></div>
  <div><div class="crit-label">Réseau</div><div class="crit-cat">${esc(reseau || 'OTN')}</div></div>
  <div><div class="crit-label">SOPs applicables</div><div class="crit-cat">${sopsArr.length} SOP(s) en ${phaseNums.length} phase(s)</div></div>
</div>`;

// Meta grid
const metaHtml = `<div class="meta-grid">
  <div class="meta-card">
    <div class="meta-card-title">Identification de l'incident</div>
    <div class="meta-row"><span class="meta-key">Référence :</span><span class="meta-val">${docId}</span></div>
    <div class="meta-row"><span class="meta-key">Catégorie :</span><span class="meta-val">${esc(categorie || incident_type || 'N/A')}</span></div>
    <div class="meta-row"><span class="meta-key">Sous-type :</span><span class="meta-val">${esc(sous_type || 'N/A')}</span></div>
    <div class="meta-row"><span class="meta-key">Réseau :</span><span class="meta-val">${esc(reseau || 'OTN')}</span></div>
  </div>
  <div class="meta-card">
    <div class="meta-card-title">Intervention</div>
    <div class="meta-row"><span class="meta-key">Site :</span><span class="meta-val">${esc(site || 'N/A')}</span></div>
    <div class="meta-row"><span class="meta-key">Technicien :</span><span class="meta-val">${esc(techStr)}</span></div>
    <div class="meta-row"><span class="meta-key">Date :</span><span class="meta-val">${esc(dateStr)}</span></div>
    <div class="meta-row"><span class="meta-key">Heure début :</span><span class="meta-val">${esc(heureStr)}</span></div>
    <div class="meta-row"><span class="meta-key">Ticket :</span><span class="meta-val">________________________</span></div>
  </div>
</div>`;

// Description bloc
const descHtml = (symptome || impact || cause_probable) ? `<div class="meta-card" style="margin-bottom:16px">
  <div class="meta-card-title">Description de l'incident</div>
  ${symptome ? '<div class="meta-row"><span class="meta-key">Symptôme :</span><span class="meta-val">' + esc(symptome) + '</span></div>' : ''}
  ${impact ? '<div class="meta-row"><span class="meta-key">Impact opérationnel :</span><span class="meta-val">' + esc(impact) + '</span></div>' : ''}
  ${cause_probable ? '<div class="meta-row"><span class="meta-key">Cause probable :</span><span class="meta-val">' + esc(cause_probable) + '</span></div>' : ''}
</div>` : '';

// Alarm block
const alarmHtml = (alarme_lightsoft || alarme_vizee) ? `<div class="alarm-block">
  <div class="alarm-title">⚡ Alarmes de référence — Signatures attendues</div>
  ${alarme_lightsoft ? '<div class="alarm-row"><span class="alarm-system">Lightsoft :</span><span class="alarm-text">' + esc(alarme_lightsoft) + '</span></div>' : ''}
  ${alarme_vizee ? '<div class="alarm-row"><span class="alarm-system">Vizee :</span><span class="alarm-text">' + esc(alarme_vizee) + '</span></div>' : ''}
</div>` : '';

// Cas réels
const casHtml = cas_reels ? `<div class="section-block cas-block">
  <div class="section-title cas-title">📋 Cas réels observés (2021-2025)</div>
  <div class="cas-text">${esc(cas_reels).replace(/\n/g, '<br>')}</div>
</div>` : '';

// KB context
let kbHtml = '';
if (contexte_kb) {
  const chunks = typeof contexte_kb === 'string' ? JSON.parse(contexte_kb) : contexte_kb;
  if (Array.isArray(chunks) && chunks.length > 0) {
    const items = chunks.map(c => `<div class="kb-item">
      <div class="kb-source">📄 ${esc(c.filename || c.source || 'Source')} <span class="kb-score">[pertinence: ${(c.score || 0).toFixed(2)}]</span></div>
      <div class="kb-text">${esc((c.text || '').slice(0, 400))}</div>
    </div>`).join('');
    kbHtml = `<div class="section-block kb-block">
  <div class="section-title kb-title">📚 Base de connaissance — Contexte technique extrait</div>
  ${items}
</div>`;
  }
}

// Phases & SOPs
let phasesHtml = '';
for (const phNum of phaseNums) {
  const ph = PHASES[String(phNum)] || PHASES[phNum] || { nom: 'Phase ' + phNum, desc: '', color: '#2c5f8a' };
  const phSops = phaseGroups[phNum];
  const sopCards = phSops.map(s => {
    const info = SOPS[s] || { nom: s, objectif: '', steps: [] };
    const stepsHtml = (info.steps || []).map(st => '<li>' + esc(st) + '</li>').join('');
    return `<div class="sop-card">
      <div class="sop-header">
        <span class="sop-badge">${s}</span>
        <span class="sop-title">${esc(info.nom)}</span>
        <span class="sop-check">☐ Validé</span>
      </div>
      ${stepsHtml ? '<ol class="sop-steps">' + stepsHtml + '</ol>' : '<div style="font-size:9.5pt;color:#555;padding:4px 0">' + esc(info.objectif) + '</div>'}
      <div class="sop-note-row">
        <span class="note-label">Notes :</span>
        <span class="note-line">_____________________________________________________________</span>
      </div>
    </div>`;
  }).join('');
  phasesHtml += `<div class="phase-block">
  <div class="phase-header" style="background:${ph.color}">
    <span class="phase-num">Phase ${phNum}</span>
    <span class="phase-nom"> — ${ph.nom}</span>
  </div>
  <div class="phase-desc">${ph.desc}</div>
  ${sopCards}
</div>`;
}

const html = `<!DOCTYPE html>
<html lang="fr">
<head>
<meta charset="UTF-8">
<style>
* { box-sizing: border-box; margin: 0; padding: 0; }
body { font-family: "Segoe UI", Arial, sans-serif; font-size: 10.5pt; color: #1a1a1a; background: #fff; padding: 15mm 18mm; }
.doc-header { border-bottom: 4px solid #0d2b52; padding-bottom: 10px; margin-bottom: 16px; display: flex; justify-content: space-between; align-items: flex-end; }
.doc-title { font-size: 18pt; font-weight: 800; color: #0d2b52; letter-spacing: -0.5px; }
.doc-subtitle { font-size: 10pt; color: #666; margin-top: 2px; }
.doc-meta { text-align: right; font-size: 8.5pt; color: #888; }
.doc-id { font-size: 14pt; font-weight: bold; color: #0d2b52; }
.crit-banner { background: #f5f5f5; border-left: 5px solid #999; padding: 10px 16px; margin-bottom: 16px; border-radius: 2px; display: flex; align-items: center; gap: 16px; flex-wrap: wrap; }
.crit-banner.crit-mineur { border-color: #2e7d32; background: #f1f8f1; }
.crit-banner.crit-majeur { border-color: #e65100; background: #fff8f5; }
.crit-banner.crit-critique { border-color: #b71c1c; background: #fff3f3; }
.crit-label { font-size: 8.5pt; color: #666; text-transform: uppercase; letter-spacing: 0.5px; }
.crit-value-mineur { font-size: 13pt; font-weight: 800; color: #2e7d32; }
.crit-value-majeur { font-size: 13pt; font-weight: 800; color: #e65100; }
.crit-value-critique { font-size: 13pt; font-weight: 800; color: #b71c1c; }
.crit-cat { font-size: 10pt; color: #444; }
.meta-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; margin-bottom: 16px; }
.meta-card { background: #f8f9fb; border: 1px solid #e0e6f0; border-radius: 4px; padding: 10px 14px; }
.meta-card-title { font-size: 8.5pt; font-weight: 700; color: #0d2b52; text-transform: uppercase; letter-spacing: 0.5px; margin-bottom: 6px; border-bottom: 1px solid #d0d8e8; padding-bottom: 4px; }
.meta-row { display: flex; gap: 8px; margin-bottom: 4px; font-size: 9.5pt; }
.meta-key { color: #666; min-width: 120px; font-weight: 600; }
.meta-val { color: #1a1a1a; flex: 1; }
.alarm-block { background: #fff8e1; border: 1px solid #ffe082; border-radius: 4px; padding: 10px 14px; margin-bottom: 16px; }
.alarm-title { font-size: 9pt; font-weight: 700; color: #b45309; text-transform: uppercase; margin-bottom: 8px; }
.alarm-row { display: grid; grid-template-columns: 140px 1fr; gap: 8px; margin-bottom: 6px; font-size: 9.5pt; }
.alarm-system { font-weight: 700; color: #555; }
.alarm-text { font-family: "Courier New", monospace; font-size: 9pt; background: #fffde7; padding: 3px 6px; border-radius: 2px; color: #1a1a1a; white-space: pre-wrap; word-break: break-all; }
.section-block { margin-bottom: 16px; border: 1px solid #e0e6f0; border-radius: 4px; overflow: hidden; }
.section-title { padding: 8px 14px; font-size: 9pt; font-weight: 700; text-transform: uppercase; letter-spacing: 0.4px; }
.kb-title { background: #e8eaf6; color: #3949ab; border-bottom: 1px solid #c5cae9; }
.cas-title { background: #e8f5e9; color: #2e7d32; border-bottom: 1px solid #c8e6c9; }
.kb-item { padding: 8px 14px; border-bottom: 1px solid #e8eaf6; font-size: 9pt; }
.kb-item:last-child { border-bottom: none; }
.kb-source { font-weight: 600; color: #3949ab; font-size: 8.5pt; margin-bottom: 4px; }
.kb-score { font-weight: normal; color: #888; }
.kb-text { color: #333; line-height: 1.5; }
.cas-text { padding: 10px 14px; font-size: 9.5pt; line-height: 1.6; color: #2e7d32; }
.sops-title { font-size: 11pt; font-weight: 700; color: #0d2b52; margin: 18px 0 12px; text-transform: uppercase; letter-spacing: 0.3px; border-bottom: 2px solid #0d2b52; padding-bottom: 6px; }
.phase-block { margin-bottom: 18px; border: 1px solid #d0d8e8; border-radius: 4px; overflow: hidden; }
.phase-header { padding: 9px 14px; color: #fff; }
.phase-num { font-weight: 800; font-size: 11pt; }
.phase-nom { font-size: 11pt; font-weight: 400; }
.phase-desc { background: #f5f7fa; padding: 7px 14px; font-size: 9pt; color: #555; font-style: italic; border-bottom: 1px solid #d0d8e8; }
.sop-card { padding: 10px 14px; border-bottom: 1px solid #e8eef8; }
.sop-card:last-child { border-bottom: none; }
.sop-header { display: flex; align-items: center; gap: 10px; margin-bottom: 8px; }
.sop-badge { background: #0d2b52; color: #fff; padding: 2px 8px; border-radius: 3px; font-weight: 700; font-size: 9pt; white-space: nowrap; }
.sop-title { font-weight: 600; font-size: 10pt; color: #0d2b52; flex: 1; }
.sop-check { font-size: 9pt; color: #888; border: 1px solid #ccc; padding: 2px 8px; border-radius: 3px; white-space: nowrap; }
.sop-steps { margin-left: 20px; font-size: 9.5pt; line-height: 1.8; color: #333; }
.sop-steps li { margin-bottom: 2px; }
.sop-note-row { display: flex; align-items: center; gap: 8px; margin-top: 8px; font-size: 9pt; color: #999; padding-top: 6px; border-top: 1px dashed #dde4ef; }
.note-label { white-space: nowrap; font-style: italic; }
.note-line { flex: 1; border-bottom: 1px solid #ccc; height: 12px; }
.sig-title { font-size: 9pt; font-weight: 700; color: #0d2b52; text-transform: uppercase; margin: 20px 0 10px; border-top: 2px solid #0d2b52; padding-top: 10px; }
.sig-grid { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 14px; margin-bottom: 16px; }
.sig-box { border: 1px solid #bbb; padding: 10px 12px; min-height: 65px; border-radius: 3px; }
.sig-label { font-size: 8.5pt; color: #666; margin-bottom: 6px; font-weight: 600; }
.sig-line { border-bottom: 1px solid #ccc; margin-top: 30px; }
.footer { margin-top: 16px; font-size: 8pt; color: #aaa; border-top: 1px solid #e0e0e0; padding-top: 6px; display: flex; justify-content: space-between; }
@media print { body { padding: 10mm 12mm; } .phase-block { page-break-inside: avoid; } .sop-card { page-break-inside: avoid; } }
</style>
</head>
<body>

<div class="doc-header">
  <div>
    <div class="doc-title">MOP — Méthode d'Opération et de Procédure</div>
    <div class="doc-subtitle">Telehouse — Réseau OTN/OOB — Procédure d'intervention NOC</div>
  </div>
  <div class="doc-meta">
    <div class="doc-id">${docId}</div>
    <div>Généré le ${genTime}</div>
    <div>v2.0 — Source: Référentiel Excel v2</div>
  </div>
</div>

${critBannerHtml}
${metaHtml}
${descHtml}
${alarmHtml}
${casHtml}
${kbHtml}

<div class="sops-title">Procédures applicables — ${sopsArr.length} SOP(s)</div>
${phasesHtml}

<div class="sig-title">Validation &amp; Clôture</div>
<div class="sig-grid">
  <div class="sig-box"><div class="sig-label">Technicien intervenant</div><div class="sig-line"></div></div>
  <div class="sig-box"><div class="sig-label">Responsable NOC</div><div class="sig-line"></div></div>
  <div class="sig-box"><div class="sig-label">Heure de clôture</div><div class="sig-line"></div></div>
</div>

<div class="footer">
  <span>${docId} — ${esc(categorie || incident_type || 'N/A')} — ${esc(sous_type || 'N/A')}</span>
  <span>Généré automatiquement par MOP Machinery v2.0 — ${genTime}</span>
</div>

</body>
</html>`;

const buf = Buffer.from(html, 'utf8');
return [{
  json: { incident_id, filename, docxFilename, html },
  binary: {
    'index.html': {
      data: buf.toString('base64'),
      mimeType: 'text/html',
      fileName: 'index.html'
    }
  }
}];
